2272→    private void savePostAndOptionallyFinish(final boolean doFinish, final boolean forceSave) {
2273→        if (mEditorFragment == null || !mEditorFragment.isAdded()) {
2274→            AppLog.e(AppLog.T.POSTS, "Fragment not initialized");
2275→            return;
2276→        }
2277→
2278→        updateAndSavePostAsyncOnEditorExit(((updatePostResult) -> {
2279→            // check if the opened post had some unsaved local changes
2280→            boolean isFirstTimePublish = isFirstTimePublish(false);
2281→
2282→            // if post was modified during this editing session, save it
2283→            boolean shouldSave = shouldSavePost() || forceSave;
2284→
2285→            mPostEditorAnalyticsSession.setOutcome(Outcome.SAVE);
2286→            ActivityFinishState activityFinishState = ActivityFinishState.CANCELLED;
2287→            if (shouldSave) {
2288→                /*
2289→                 * Remote-auto-save isn't supported on self-hosted sites. We can save the post online (as draft)
2290→                 * only when it doesn't exist in the remote yet. When it does exist in the remote, we can upload
2291→                 * it only when the user explicitly confirms the changes - eg. clicks on save/publish/submit. The
2292→                 * user didn't confirm the changes in this code path.
2293→                 */
2294→                boolean isWpComOrIsLocalDraft = mSite.isUsingWpComRestApi() || mEditPostRepository.isLocalDraft();
2295→                if (isWpComOrIsLocalDraft) {
2296→                    activityFinishState = savePostOnline(isFirstTimePublish);
2297→                } else if (forceSave) {
2298→                    activityFinishState = savePostOnline(false);
2299→                } else {
2300→                    activityFinishState = ActivityFinishState.SAVED_LOCALLY;
2301→                }
2302→            }
2303→            // discard post if new & empty
2304→            if (isDiscardable()) {
2305→                mDispatcher.dispatch(PostActionBuilder.newRemovePostAction(mEditPostRepository.getEditablePost()));
2306→                mPostEditorAnalyticsSession.setOutcome(Outcome.CANCEL);
2307→                activityFinishState = ActivityFinishState.CANCELLED;
2308→            }
2309→            if (doFinish) {
2310→                mViewModel.finish(activityFinishState);
2311→            }
2312→        }));
2313→    }
