2318→
2319→        boolean existingPostWithChanges = mEditPostRepository.hasPostSnapshotWhenEditorOpened() && hasChanges;
2320→        // if post was modified during this editing session, save it
2321→        return isPublishable && (existingPostWithChanges || isNewPost());
